INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 2, 0, 1, 52001, 1, "ペコリーヌの満腹ツインおにぎり", 1, 51001, 0, "500マイルを獲得する。", 1, 2, "次に振るダイスが2個に増える。出目の合計の数だけ進める。", "ペコリーヌの\n満腹ツインおにぎり", "ペコリーヌが丹精込めて握った特大おにぎり。\nごはんは命のエネルギーを体現しているらしい。\n普通の人が満腹に感じる量の倍のサイズの中に\n最高級の具を閉じ込めた【美食殿】らしい一品。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 2, 0, 1, 52002, 2, "コッコロのゆるりと休憩サラダ", 1, 51002, 0, "500マイルを獲得する。", 3, 30001, "このターンに振るダイスの目が必ず「1」になる。さらに、次のターン数のカウントをスキップする。", "コッコロの\nゆるりと休憩サラダ", "コッコロが皆のことを思って用意したサラダ。\n栄養バランスも考えられたうえに腹持ちもよく\n味だけではなく見た目にも気を配られている。\n冒険への活力を与えてくれる慈愛溢れる一品。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52003, 1, "キャルの絶品五つ星バーガー", 1, 51003, 0, "平凡な未鑑定トレジャーを1個獲得する。", 2, 20004, "このターンに振るダイスの目が必ず「5」になる。", "キャルの\n絶品五つ星バーガー", "キャルが食べたい物を挟み込んだハンバーガー。\n香ばしいパンとお肉の香りが食欲を刺激する。\n魔物でない素材で作られた、冒険中に食べるには\nゴージャスすぎる一品、とキャルは信じている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 4, 0, 1, 52004, 3, "リリのコツコツまい進かしわ餅", 3, 51004, 0, "800マイルを獲得する。", 2, 20001, "ダイスを3回振るまでの間、ダイスの目が必ず「4」になる。", "リリのコツコツ\nまい進かしわ餅", "リリが作った柏餅……の中でも、上手く作れた\n選りすぐりの品。最高の素材を使用した上、\n失敗した分はリリが自分で食べてしまったため\n単価でみるとかなりの高級品となっている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 3, 52005, 3, "クリアの彩り華やかバラエティ弁当", 0, 51005, 0, "次にダイスを振った際、1マス多く進める。", 4, 1, "ランダムなイベントを発生させる。", "クリアの彩り華やか\nバラエティ弁当", "クリアが朝早くから用意した冒険用のお弁当。\nおかずは様々でどれも絶品だが、どんなものが\n入っているかはみんなにも秘密にされているため\n蓋を開けるまでのお楽しみとなっている。", 11);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 4, 0, 1, 52006, 1, "プレシアの食いしん坊ぶーぶー肉まん", 1, 51006, 0, "800マイルを獲得する。", 2, 20002, "このターンに振るダイスの目が「4・5・6」のみになる。", "プレシアの食いしん坊\nぶーぶー肉まん", "プレシアが選び抜いた具を詰め込んだ肉まん。\n彼女の希望で、通常の肉まんの数倍のサイズに\nなっている。味もボリュームも満点でハッピー\n間違いなしですよ♪とは調理担当クリアの談。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 3, 0, 1, 52007, 1, "カヤとイノリの食欲倍増ケバブサンド", 2, 51007, 0, "福引券を1枚獲得する。", 7, 1, "このターンに振るダイスの目を必ず「3」に、次のターンに振るダイスの目を必ず「6」にする。", "カヤとイノリの\n食欲倍増ケバブサンド", "カヤとイノリが弁当代わりに持ってきたケバブ。\nイノリ行きつけの店の硬派な味わいで、ギャング\nとしてのやる気が一人3倍、コンビで6倍となり\n下剋上を成し遂げるパワーが湧く……らしい。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 2, 1, 2, 52008, 2, "タマキの金運招くレインボーたい焼き", 0, 51008, 0, "500マイルを獲得する。", 5, 200, "次にマイルマスに止まった際の獲得マイルが200%アップする。", "タマキの金運招く\nレインボーたい焼き", "タマキたちが『ジオ・テオゴニア』に持ち込んだ\nたい焼きの概念が現地の文化と溶け合い生まれた\n魔改造スイーツ。虹色に輝くその甘さは、実に\nランドソルのたい焼きの数倍と言われている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52009, 2, "クローチェのフルパワーポテトサラダ", 2, 51009, 1, "平凡な未鑑定トレジャーを1個獲得する。", 7, 1, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「8」に、次のターンに振るダイスの目を必ず「1」にする。", "クローチェの\nフルパワーポテトサラダ", "クローチェがフルパワーで作ったポテトサラダ。\n本来はガレットを作ろうとしたが、うっかり\n握り潰してしまったため、軌道修正して仕上げ\nた一品。経緯はともかく味は非常に美味である。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 2, 2, 2, 52010, 3, "アヤネとクルミの青空ピクニックセット", 0, 51010, 0, "500マイルを獲得する。", 6, 1, "マップ上の「マイルマス」「トレジャーマス」 「ショップマス」のRANKが1つ上がる。効果は対象のマスに計2回止まるまで継続する。", "アヤネとクルミの\n青空ピクニックセット", "アヤネとクルミが二人で用意した特別なランチ\nバスケット。仲間との冒険への希望が詰まった\nご機嫌な料理の数々で、道中の様々な出来事が\n１ランク上のイベントに感じられるようになる。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 3, 0, 1, 52011, 3, "リマの不思議なスイートアップル", 2, 51011, 0, "福引券を1枚獲得する。", 7, 1, "このターンに振るダイスの目を必ず「2」に、次のターンに振るダイスの目を必ず「7」にする。", "リマの不思議な\nスイートアップル", "リマがネネカにもらったリンゴで作った秘密の\nスイーツ。爽やかな酸味と濃厚な甘さがまるで\n魔法のようなバランスでお互いを引きたてており\n食べた者をたちまち虜にしてしまうという。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52012, 2, "ニノンのオリジナル一二三寿司", 1, 51012, 0, "平凡な未鑑定トレジャーを1個獲得する。", 3, 30002, "このターンに振るダイスの目が「1・2・3」のみになる。さらに、次のターン数のカウントをスキップする。", "ニノンのオリジナル\n一二三寿司", "ニノンがジオ・テオゴニアに持ち込んだ特別な\n寿司。厳選された新鮮な魚介を使った逸品だが、\n一部のネタは、寿司のセオリーを逸脱したニノン\n我流のものに仕上がっている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 4, 0, 3, 52013, 3, "クレジッタの開運お菓子盛り合わせ", 0, 51013, 0, "800マイルを獲得する。", 8, 2, "RANK2のマイルショップを開く。", "クレジッタの開運\nお菓子盛り合わせ", "クレジッタが考案した、ジオ・テオゴニアで流通\nしているチョコの貨幣の盛り合わせ。一見すると\n金貨を口に入れるおバカさんではあるが、通貨を\n食べるという背徳感が隠し味となっている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52014, 2, "リノの「時は金時」かき氷", 2, 51014, 0, "次にダイスを振った際、1マス多く進める。", 9, 1, "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", "リノの\n「時は金時」かき氷", "可愛い妹がお兄ちゃんのために心を込めて作った\nスペシャルなかき氷。一口食べるとたちどころに\nクールな甘さが精神を研ぎ澄まし、いかなる\nお得をも見逃さない要塞賢母と化すという。", 11);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52015, 1, "シズルの愛情盛り盛りハンバーグ", 1, 51015, 0, "次にダイスを振った際、1マス多く進める。", 1, 2, "次に振るダイスが2個に増える。出目の合計の数だけ進める。", "シズルの愛情\n盛り盛りハンバーグ", "お姉ちゃんが弟くんのために心を込めて作った\nスペシャルなハンバーグ。アツアツの肉汁と共に\n溢れんばかりの愛が詰まっており、一口食べる\nだけで、走り回りたくなるような美味しさ。", 11);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52016, 3, "アオイの疾走サンドイッチ", 1, 51016, 0, "なし", 2, 20005, "このターンに振るダイスの目が必ず「6」になる。", "アオイの疾走\nサンドイッチ", "アオイがお弁当として作ったエルフ伝統の野菜\nサンド。一緒についてきてくれる最高の友だち\nの助言により、どんなに深い森の中でも全速力\nで駆け抜けることができるらしい。（アオイ談）", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 5, 0, 1, 52017, 3, "クウカの緊縛触手活け造り", 2, 51017, 1, "なし", 2, 1, "[FF7C4E,D62146]【上書き不可】[-]次のターン「移動系カテゴリーの料理」が食べられない代わりに、その場で2000マイルを獲得する。", "クウカの緊縛\n触手活け造り", "数多くのドM妄想をしてきたクウカの中で最近の\nマイブームである触手をモチーフとした活造り。\n新鮮な蛸足が、濃厚なうま味と共に物理的に絡み\n付き身も心も縛りあげられる様な体験ができる。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 6, 0, 1, 52018, 1, "ランファの世話焼き三昧肉じゃが", 1, 51018, 0, "1000マイルを獲得する。", 2, 20006, "このターンに振るダイスの目が必ず「3」になる。", "ランファの世話焼き三昧肉じゃが", "コッコロの指導により料理の腕を上げたランファ\nが手作りした肉じゃが。まだ改善の余地はある\nものの、不器用なランファが誰かのために積み\n重ねた努力を思うととてもおいしく味わえる。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52019, 1, "ワカナの節約腹八分目カレー", 1, 0, 0, "なし", 2, 20007, "このターンに振るダイスの目が必ず「8」になる。", "ワカナの節約腹八分目カレー", "バンディ・シスターズの昨夜の夕食カレー。作り\n過ぎて食べきれずにいたものをワカナがお裾分け\nしてくれた。寝かされていたためしっかりと味の\n染みた、極上の二日目カレーとなっている。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 2, 52020, 2, "リノの「時は金時」かき氷", 2, 51014, 0, "次にダイスを振った際、1マス多く進める。", 9, 1, "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", "リノの\n「時は金時」かき氷", "可愛い妹がお兄ちゃんのために心を込めて作った\nスペシャルなかき氷。一口食べるとたちどころに\nクールな甘さが精神を研ぎ澄まし、いかなる\nお得をも見逃さない要塞賢母と化すという。", 11);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 7, 0, 2, 52021, 3, "カスミの真実見抜くボンボン・ショコラ", 3, 51021, 0, "	平凡な未鑑定トレジャーを2個獲得する。", 9, 2, "トレジャーマスをスキップして移動できる。効果は3ターンの間継続する。", "カスミの真実見抜く\nボンボン・ショコラ", "綺麗な装飾箱に納められたボンボン・ショコラ。\nそのほろ苦さを秘めた濃密な甘さが灰色の脳細胞\nに働きかける時、名探偵の鋭い推理が隠された\n謎を全て白日の下へと晒し、事件を解決へ導く。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52022, 1, "アキノのゲヘニアンチキンプレート", 3, 51022, 0, "なし", 2, 20008, "ダイスを3回振るまでの間、「5と6」の⽬が出る確率が3倍になる。", "アキノのゲヘニアン\nチキンプレート", "アキノがジオ・ゲヘナで仕入れてきたスパイスを\n使用した、お洒落で豪華なチキンプレート。牧場\n特製ヨーグルトソースと奏でる刺激的な味わいは\nまさに二つの世界の奇跡のマリアージュである。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52023, 1, "ミミのコロコロお手玉おにぎり", 2, 51023, 1, "平凡な未鑑定トレジャーを1個獲得する。", 7, 1, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「6」に、次のターンに振るダイスの目を必ず「3」にする。", "ミミのコロコロ\nお手玉おにぎり", "ミミが、ジオ・ゲヘナで助けてくれたお姉さん達\nのことを思い作ったおにぎり。それぞれ異なる\n味付けがされているが、ミミの願い通りお互いに\nケンカをせず仲良くハーモニーを奏でている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 3, 0, 3, 52024, 3, "アユミの隠密ガトーインビジブル", 0, 51024, 0, "次にダイスを振った際、3マス多く進める。", 8, 2, "RANK2のマイルショップを開く。", "アユミの隠密\nガトーインビジブル", "気が付くとリリの手元にあった不思議なお菓子。\n一見普通のケーキだが、内部に様々な具材が\n隠れるように入っている。複雑で重層的な\n味わいを見せる様は、まるで誰かさんのよう。", 11);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 2, 52025, 3, "アネモネの花爛漫ステーキサラダ", 1, 51025, 0, "なし", 9, 3, "「マイルマス」「トレジャーマス」をスキップして移動できる。効果は1ターンの間継続する。", "アネモネの\n花爛漫ステーキサラダ", "アネモネが世話する秘密の菜園の野菜を使った\nサラダ。栄養を重視するアネモネは草食獣の肉を\n野菜と解釈、当初は野菜の上に肉を置いただけ\nであったが、ネラの指導で盛り付け直された。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 8, 0, 3, 52026, 1, "アンナの煉獄蕃茄煮混沌卵", 0, 51026, 0, "福引券を2枚獲得する。", 4, 1, "ランダムなイベントを発生させる。", "アンナの\n煉獄蕃茄煮混沌卵", "ジオ・ゲヘナを探索中の冥姫たちが現地で採取\nしたスパイスで味付けした一皿。赤く煮え滾る\nソースは刺激的かつ非常に奥深い味わいで未知の\n大地の如く冒険者たちをその深奥へと誘う。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52027, 3, "ユイの栄養満点まごころ弁当", 2, 51027, 0, "なし", 2, 20004, "ダイスを2回振るまでの間、ダイスの目が必ず「5」になる。", "ユイの\n栄養満点まごころ弁当", "ユイが食べる人のことを考え、心を込めて作った\nお弁当。程よいサイズのお弁当箱に愛情と手間暇\nをたっぷりとかけた極上の料理が詰まっており、\n食べた者の心と胃袋を優しく満たしてくれる。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 9, 0, 1, 52028, 3, "リンのナッツ入りぐうたらあんパン", 1, 51028, 0, "なし", 2, 30003, "このターンに振るダイスの目が「1・2」のみに\nなる代わりに、その場で福引券を3枚獲得する。", "リンの\nナッツ入りぐうたらあんパン", "リンからもらった非常食のあんパン。ナッツが\n練り込まれクランチな食感で食べ飽きない。\nゲームのため部屋に引きこもる際のお供であり、\n必要な栄養素が全て賄える完全栄養食、らしい。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52029, 2, "シェフィの氷晶煌めく手作りアイス", 1, 51029, 0, "なし", 3, 30004, "このターンに振るダイスの目が必ず「2」になる。さらに、次のターン数のカウントをスキップする。", "シェフィの\n氷晶煌めく手作りアイス", "シェフィが自身の魔力の氷を使い作ったアイス。\nペコリーヌにねだられて作ったものだがキャル達\nにも好評である。コッコロ曰くひんやりしている\nのに食べると心が温かくなってきます、との事。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 3, 52030, 1, "ミソラの気まぐれ味噌ラーメン★", 3, 51030, 0, "なし", 12, 1, "3ターンの間、すべての「マイルマス」をランク3の「トレジャーマス」に変化させる。", "ミソラの\n気まぐれ味噌ラーメン★", "ミソラが作ったラーメン。適当に言った好きな物\nをランファが憶えていたために、材料を用意され\n仕方なく作ったものだが味はイイコト級の一品。\n美味しそうに食べられるのは嫌いではない様子。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52031, 3, "イロハの最強クワガタゼリー（人間用）", 1, 51031, 0, "なし", 2, 20009, "このターンに振るダイスの目が「1・6・6・6・8・8」になる。", "イロハの\n最強クワガタゼリー（人間用）", "イロハがいつも持ち歩いているカラフルなゼリー\n…なのだがアルケス錬金堂で作られたクワガタ用\n餌ゼリーとそっくりな見た目をしている。甘くて\n美味しいが、人間用か尋ねると目を逸らされる。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 3, 0, 2, 52032, 3, "グレイスの目ん玉飛び出るカップケーキ", 2, 51032, 0, "次にダイスを振った際、3マス多く進める。", 9, 4, "料理マスをスキップして移動できる。効果は2ターンの間継続する。", "グレイスの\n目ん玉飛び出るカップケーキ", "グレイスお手製のカップケーキ。ショッキングな\n見た目に全振り…と思わせて目玉も食べることが\n可能で大変美味…と思わせて一部だけ魂消るほど\n甘い部分がある。原材料は頑なに秘されている。", 11);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 3, 52033, 1, "ソノの今日は特別ご褒美オムライス", 0, 51033, 0, "なし", 8, 3, "RANK3のマイルショップを開く。", "ソノの今日は特別ご褒美オムライス", "ソノが作ったオムライス。イロハの大好物であり\n家庭の味。普段は面倒くさがりやらないがイロハ\nが良い子の時はケチャップでクワガタを描いて\nあげている。その時は普段より美味しいらしい。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 2, 52034, 1, "ジータのグリルド・グラッジチャンク", 2, 51034, 0, "平凡な未鑑定トレジャーを1個獲得する。", 9, 1, "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", "ジータの\nグリルド・グラッジチャンク", "そのあまりの美味さと、ほとばしるカロリーから\n悪意の塊、という物騒な名が付けられた肉料理。\nこの肉を集められるかが騎空士としての力量を\n示すため、ジータは大量に集めたがっている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 10, 0, 3, 52035, 1, "ルイズマリーの成功しすぎてるフライ", 0, 51035, 0, "貴重な未鑑定トレジャーを1個獲得する。", 4, 1, "ランダムなイベントを発生させる。", "ルイズマリーの\n成功しすぎてるフライ", "ルイズマリーが祖母のレシピを忠実に再現した\n最高傑作。精緻な調合と温度管理が生み出す衣と\n身のサクフワは錬金技術の到達点と言われている\nが、ただの料理なのではとの意見も絶えない。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52036, 3, "ホウオウの食べる権利をあげます！饅頭", 3, 51036, 1, "なし", 7, 1, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「12」に、次とさらにその次のターンに振るダイスの目を必ず「1」にする。", "ホウオウの\n食べる権利をあげます！饅頭", "ジオ・ゲヘナの空の覇者にして煉華のホウオウが\n己への信仰心を集めるべく作らせたお菓子。中の\n餡はしっとり甘く、上品な味わい。ジオ・ゲヘナ\n銘菓の名を恣にする日も近い、かもしれない。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 11, 1, 2, 52037, 3, "魔法少女ナナカちゃんウエハース", 0, 51037, 0, "平凡な未鑑定トレジャーを3個獲得する。", 6, 1, "マップ上の「マイルマス」「トレジャーマス」 「ショップマス」のRANKが1つ上がる。効果は対象のマスに計1回止まるまで継続する。", "魔法少女\nナナカちゃんウエハース", "ナナカ考案＆監修のウエハース。おまけシールの\nコレクション性を高くした結果ランドソル中で\n大ブーム…だが肝心の菓子が棄てられる事態に。\n解決のため、王女が自ら口を開いたのだった。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 3, 0, 1, 52038, 1, "アリサがお届け♪リノセウスの包み焼き", 1, 51038, 0, "福引券を1枚獲得する。", 1, 2, "次に振るダイスが2個に増える。出目の合計の数だけ進める。", "アリサがお届け♪\nリノセウスの包み焼き", "アリサ特製の包み焼き。伝承の怪物とよく似た\n魔物を材料にしているため、いつしかその怪物と\n同じ名で呼ばれるようになったという。鋭い鎌と\n火傷に気を付けながら、熱々を召し上がれ。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 3, 52039, 2, "イリヤの†ブラッディ†トマトジュース", 2, 51039, 0, "なし", 12, 2, "2ターンの間、すべての「マイルマス」をランク3の「ショップマス」に変化させる。", "イリヤの†ブラッディ†\nトマトジュース", "イリヤの愛飲する赤く鮮やかなトマトジュース。\n伝説の吸血鬼に相応しいクオリティを、と求めた\n末に辿り着いた究極の逸品。しかしお値段も相応\nに張るため、特別な時にしか飲めないらしい。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 2, 0, 2, 52040, 1, "マツリの活力源～騎士団遠征プレート～", 3, 51040, 0, "次にダイスを振った際、2マス多く進める。", 9, 2, "トレジャーマスをスキップして移動できる。効果は3ターンの間継続する。", "マツリの活力源\n～騎士団遠征プレート～", "【王宮騎士団】遠征時の定番メニューにマツリが\nアレンジを加え調理したプレート。苦手な野菜を\nなくしてお肉倍増を目論んだのが配膳前にバレ、\nジュンの指導できちんと野菜も入れさせられた。", 11);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52041, 1, "ヴァンピィちゃんのさいきょースープ", 2, 51041, 1, "平凡な未鑑定トレジャーを1個獲得する。", 7, 1, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「7」に、次のターンに振るダイスの目を必ず「2」にする。", "ヴァンピィちゃんの\nさいきょースープ", "ヴァンピィがよく振舞ってくれる特製スープ。\nどうやら家庭料理のようで、素朴な味わいが\n人々を郷愁へと誘う。昔誰かと並んで一緒に\n肉団子を作ったような…とはヴァンピィの言葉。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 1, 52042, 2, "アイラのみんなで飲みたい赤麦しゅわ", 2, 51042, 0, "なし", 2, 20002, "ダイスを2回振るまでの間、出る目が「4・5・6」のみになる", "アイラのみんなで\n飲みたい赤麦しゅわ", "アイラが愛する赤麦しゅわ。彼女の熱い要望で\n酩酊感ゼロの子供向けも生産開始した。曰くこの\n美味しさを広めるためとのことだが、本当は単に\n老若男女皆で楽しく飲みたいだけかもしれない。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 12, 0, 1, 52043, 1, "レイの釣りたて鮮魚七輪塩焼き", 2, 51043, 1, "なし", 2, 1, "[FF7C4E,D62146]【上書き不可】[-]次のターン「移動系カテゴリーの料理」が食べられない代わりに、その場で貴重な未鑑定トレジャーを3個獲得する。", "レイの釣りたて\n鮮魚七輪塩焼き", "レイが釣った魚の塩焼き。試行錯誤の末に理想の\n塩と火の加減にたどり着いた。調理は真剣勝負で\n釣りと同様、己の心との戦いだという。レイも\n時々、集中しすぎて仲間に心配されているとか。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 3, 0, 1, 52044, 2, "ユキノ製ごろっと果実のかちこち氷菓子", 1, 51044, 0, "福引券を1枚獲得する。", 3, 30002, "このターンに振るダイスの目が「1・2・3」のみになる。さらに、次のターン数のカウントをスキップする。", "ユキノ製ごろっと果実の\nかちこち氷菓子", "ユキノが偶然生み出した、青果実のアイスバー。\n元は誤って凍らせたものだが爽やかな味が好評で\nなんと久遠氷河を代表する手土産に。伸び続ける\n売り上げに本人が一番溶けそうになっている。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 4, 0, 2, 52045, 3, "サレンの思い出ぎっしり焼きそばパン", 3, 51045, 0, "800マイルを獲得する。", 9, 5, "「ショップマス」「ミニゲームマス」「イベントマス」をスキップして移動できる。効果は3ターンの間継続する。", "サレンの思い出ぎっしり\n焼きそばパン", "サレンが作った思い出の焼きそばパン。どっしり\nしたボリュームある炭水化物×炭水化物の信頼感\nで皆を笑顔に変える。専用の皿に盛り付けたら見\n栄えも十分。カロリーは気にしないのがお作法。", 10);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 0, 0, 2, 52046, 1, "アラクネの肉マシマシマシ炒め野菜入り", 3, 51046, 0, "なし", 9, 1, "マイルマスをスキップして移動できる。効果は3ターンの間継続する。", "アラクネの肉マシマシマシ炒め\n野菜入り", "アラクネが初めて覚えた料理。周囲の人々が自分\nより小さいのは小食が理由と思っているらしく、\nたくさん食べて大きくなってほしいという優しさ\nから、超ボリュームなデカ盛り仕様となった。", 0);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (500, 1, 0, 1, 52047, 1, "シナツの極うな重　韋駄天仕上げ", 1, 51047, 0, "平凡な未鑑定トレジャーを1個獲得する。", 1, 2, "次に振るダイスが2個に増える。出目の合計の数だけ進める。", "シナツの極うな重\n韋駄天仕上げ", "胃に入れば何でも同じ、が信条のシナツが自分で\n釣った鰻で拵えたうな重。レイの協力のもと練習\nを重ね、見た目も味も合格点に到達した。一番\n苦労したのは調理場を破壊しない力加減だとか。", 10);
